import type {
  AuthPluginComponents,
  AuthPlugin as AuthPluginPrimitive
} from "@better-auth-ui/react"

declare module "@better-auth-ui/core" {
  /** Widens `useAuth().plugins` to the shadcn-typed `AuthPlugin`. */
  interface AuthPluginRegister {
    shadcn: AuthPlugin
  }
}

/** Props the shadcn `<Auth>` router spreads onto plugin-contributed auth views. */
export type AuthViewProps = {
  className?: string
  socialLayout?: "auto" | "horizontal" | "vertical" | "grid"
  socialPosition?: "top" | "bottom"
}

/** Props the shadcn `<Settings>` router spreads onto plugin-contributed settings views. */
export type SettingsViewProps = {
  className?: string
}

/** Shadcn plugin type. Plugin authors import this from `@/lib/auth/auth-plugin`. */
export type AuthPlugin = AuthPluginPrimitive<
  AuthPluginComponents,
  AuthViewProps,
  SettingsViewProps
>

import { createAuthPlugin } from "@better-auth-ui/core"
import {
  themePlugin as coreThemePlugin,
  type ThemeLocalization
} from "@better-auth-ui/core/plugins"

import { Appearance } from "@/components/auth/theme/appearance"
import { ThemeToggleItem } from "@/components/auth/theme/theme-toggle-item"

/**
 * Hook shape compatible with `next-themes`' `useTheme` and similar APIs. The
 * hook is invoked inside the plugin factory so consumers can register the
 * plugin in the same component as their `<ThemeProvider>` without an extra
 * inner component.
 */
export type UseThemeHook = () => {
  theme?: string
  setTheme: (theme: string) => void
  themes?: string[]
}

type CommonThemeOptions = {
  /**
   * Override the plugin's default localization strings.
   * @remarks `ThemeLocalization`
   */
  localization?: Partial<ThemeLocalization>
  /**
   * Available theme options.
   * @default ["system", "light", "dark"]
   */
  themes?: string[]
}

export type ThemePluginOptions = CommonThemeOptions &
  (
    | {
        /**
         * A theme hook (e.g. next-themes' `useTheme`) called inside the
         * plugin's slot components on every render. The hook owns the live
         * theme value, so `theme`/`setTheme` are not accepted in this form.
         */
        useTheme: UseThemeHook
        theme?: never
        setTheme?: never
      }
    | {
        /**
         * Current theme value. Required when not using a hook so slot
         * components can highlight the active option. Pass it from a
         * stateful source (e.g. `useState`, Context) so updates flow
         * through `<AuthProvider>` and re-render slot components.
         * @remarks Do not memoize the static call (e.g. wrap
         * `themePlugin({ theme, setTheme })` in `useMemo`): `theme` is
         * captured at factory-creation time, so a memoized closure will
         * keep returning the stale value and slot components will stop
         * reflecting theme changes. Let the factory re-run each render.
         */
        theme: string
        /** Setter that updates the value `theme` is read from. */
        setTheme: (theme: string) => void
        useTheme?: never
      }
  )

export const themePlugin = createAuthPlugin(
  coreThemePlugin.id,
  ({ useTheme, ...rest }: ThemePluginOptions) => {
    // No-op `setTheme` baseline keeps core's required option satisfied on the
    // hook branch (where the consumer doesn't pass a setter); on the static
    // branch the spread overrides it with the consumer's real setter.
    const base = coreThemePlugin({ setTheme: () => {}, ...rest })
    return {
      ...base,
      // Slot components always call `plugin.useTheme()` — invoking the hook
      // inside their render keeps it in scope of any `<ThemeProvider>` the
      // consumer mounts. On the static branch the factory re-runs on every
      // parent render, so the synthesized closure stays in sync with the
      // consumer's `theme` state.
      useTheme:
        useTheme ??
        (() => ({
          theme: base.theme,
          setTheme: base.setTheme,
          themes: base.themes
        })),
      userMenuItems: [ThemeToggleItem],
      accountCards: [Appearance]
    }
  }
)

"use client"

import { useAuthPlugin } from "@better-auth-ui/react"
import { Monitor, Moon, PaletteIcon, Sun } from "lucide-react"
import { useRef } from "react"

import { DropdownMenuItem } from "@/components/ui/dropdown-menu"
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { themePlugin } from "@/lib/auth/theme-plugin"

/**
 * Theme toggle dropdown item used inside `UserButton`. Callers are responsible
 * for ensuring theming is configured before rendering this component.
 */
export function ThemeToggleItem() {
  const { useTheme, localization } = useAuthPlugin(themePlugin)
  const { theme, setTheme, themes = [] } = useTheme()
  const tabsListRef = useRef<HTMLDivElement>(null)

  // The TabsTriggers aren't part of the menu's roving focus group, so
  // arrow-key navigation can't reach them on its own. When the wrapper
  // menu item receives focus we delegate focus to the active TabsTrigger
  // inside, letting the user switch themes with Left/Right arrows.
  const focusActiveTab = () => {
    const activeTab = tabsListRef.current?.querySelector<HTMLElement>(
      '[role="tab"][data-state="active"]'
    )
    activeTab?.focus({ preventScroll: true })
  }

  // Up/Down on a TabsTrigger escapes back to the previous/next sibling
  // menu item so users can keep navigating the menu with the arrow keys.
  const handleTabsKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (event.key !== "ArrowUp" && event.key !== "ArrowDown") return

    const target = event.target as HTMLElement
    if (target.getAttribute("role") !== "tab") return

    const wrapper = target.closest<HTMLElement>('[role="menuitem"]')
    const content = wrapper?.closest<HTMLElement>("[data-radix-menu-content]")
    if (!wrapper || !content) return

    const items = Array.from(
      content.querySelectorAll<HTMLElement>(
        '[role="menuitem"]:not([aria-disabled="true"])'
      )
    )
    const currentIndex = items.indexOf(wrapper)
    const nextIndex =
      event.key === "ArrowDown" ? currentIndex + 1 : currentIndex - 1
    const next = items[nextIndex]
    if (!next) return

    event.preventDefault()
    next.focus()
  }

  return (
    <DropdownMenuItem
      asChild
      onSelect={(e) => e.preventDefault()}
      onFocus={(e) => {
        // onFocus bubbles in React, so guard against re-entry from focus
        // events fired by the inner TabsTrigger.
        if (e.target === e.currentTarget) focusActiveTab()
      }}
    >
      <div>
        <PaletteIcon className="text-muted-foreground" />

        <span>{localization.theme}</span>

        <Tabs
          className="ml-auto"
          value={theme}
          onValueChange={setTheme}
          onKeyDown={handleTabsKeyDown}
        >
          <TabsList ref={tabsListRef} className="h-6!">
            {themes.includes("system") && (
              <TabsTrigger
                value="system"
                className="size-5 p-0"
                aria-label={localization.system}
              >
                <Monitor className="size-3" />
              </TabsTrigger>
            )}
            {themes.includes("light") && (
              <TabsTrigger
                value="light"
                className="size-5 p-0"
                aria-label={localization.light}
              >
                <Sun className="size-3" />
              </TabsTrigger>
            )}
            {themes.includes("dark") && (
              <TabsTrigger
                value="dark"
                className="size-5 p-0"
                aria-label={localization.dark}
              >
                <Moon className="size-3" />
              </TabsTrigger>
            )}
          </TabsList>
        </Tabs>
      </div>
    </DropdownMenuItem>
  )
}
